//----------Build function to build the dialog of backprofile Main UI STARTS-----------------------------------//
void MRFBackProfileDlg::Build()
{
	//Create Dlg Object
	_pMainFrame = new CATDlgFrame(this, (const char*)"MainFrame", 0 | CATDlgGridLayout | CATDlgFraNoTitle | CATDlgFraNoFrame);
	_lblSelectorListResultJoinSurface = new CATDlgLabel(_pMainFrame, (const char*)"Source Surface", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_selectorListResultJoinSurface = new CATDlgSelectorList(_pMainFrame, (const char*)"Source Surface SelList", CATDlgLabCenter | CATDlgLabRight);

	_lblSelectorListVentSet = new CATDlgLabel(_pMainFrame, (const char*)"Vents Geometrical Set", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_selectorListVentSet = new CATDlgSelectorList(_pMainFrame, (const char*)"VentGeomSet SelList", CATDlgLabCenter | CATDlgLabRight);
	   
	_contextMenuClearSelectionSourceSurf = new CATDlgContextualMenu(_selectorListResultJoinSurface, (const char*)"Clear SourceSurface", CATDlgCtxEmpty);
	_contextMenuClearSelectionVentGeomSet = new CATDlgContextualMenu(_selectorListVentSet, (const char*)"Clear BaldSurface", CATDlgCtxEmpty);

	_pBackProfileFrame = new CATDlgFrame(_pMainFrame, (const char*)"BackProfile Frame", 0 | CATDlgGridLayout | CATDlgFraNoTitle | CATDlgFraNoFrame);

	_lblComboBoxPartList = new CATDlgLabel(_pBackProfileFrame, (const char*)"Back Profile/Part", CATDlgLabLeft | CATDlgLabRight | CATDlgLabCenter);
	_comboBoxPartList = new CATDlgCombo(_pBackProfileFrame, (const char*)"ComboBox BackProfileList", CATDlgCmbDropDown);
	_comboBoxPartList->SetDropDownTextWidth(15);
	_comboBoxPartList->SetVisibleTextWidth(15);

	_pushButtonInstantiateBackProfile = new CATDlgPushButton(_pBackProfileFrame, (const char*)"Instantiate", CATDlgPusRepetitive);
	_multiListOnParmInput = new CATDlgMultiList(_pBackProfileFrame, (const char*)"MultiList Parm");

	//SetGridConstraints
	_pMainFrame->SetGridConstraints(0, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);


	_lblSelectorListResultJoinSurface->SetGridConstraints(0, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_selectorListResultJoinSurface->SetGridConstraints(0, 1, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);

	_lblSelectorListVentSet->SetGridConstraints(1, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_selectorListVentSet->SetGridConstraints(1, 1, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);

	_pBackProfileFrame->SetGridConstraints(2, 0, 2, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);

	_lblComboBoxPartList->SetGridConstraints(0, 0, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_comboBoxPartList->SetGridConstraints(0, 1, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_pushButtonInstantiateBackProfile->SetGridConstraints(0, 2, 1, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	_multiListOnParmInput->SetGridConstraints(1, 0, 2, 1, 0 | CATGRID_LEFT | CATGRID_RIGHT | CATGRID_TOP | CATGRID_BOTTOM);
	
	
	
	_pushButtonInstantiateBackProfile->SetSensitivity(CATDlgDisable);
	
	//Set Properties Of Dlg Object
	_selectorListResultJoinSurface->SetVisibleTextHeight(1);
	_selectorListResultJoinSurface->SetVisibleTextWidth(15);
	_selectorListResultJoinSurface->SetLine(SelctorListDefVal);

	_selectorListVentSet->SetVisibleTextHeight(1);
	_selectorListVentSet->SetVisibleTextWidth(15);
	_selectorListVentSet->SetLine(SelctorListDefVal);

	CATUnicodeString columnTitle[2];
	columnTitle[0] = "Parameter Name";
	columnTitle[1] = "Parameter Value";
	_multiListOnParmInput->SetColumnTitles(2, columnTitle);
	_multiListOnParmInput->SetColumnEditable(1, true);
	_multiListOnParmInput->SetVisibleColumnCount(2);
	_multiListOnParmInput->SetVisibleLineCount(5);

	this->SetPREVIEWSensitivity(CATDlgDisable);

}
