//-----------Function to set focus on selector List when selector list is clicked by user STARTS--------------//
void MRFBackProfileDlg::SetFocusOnSelectorList(CATDlgSelectorList * ipSelectorList)
{
	if (!!ipSelectorList)
	{
		static int arrRow[1] = { 0 };
		ipSelectorList->SetSelect(arrRow, 1, 0);
		SetFocusOn(ipSelectorList);

	}
}
//-----------Function to set focus on selector List when selector list is clicked by user STARTS--------------//

//------------Function to set name to be displayed at Surface Selector List STARTS------------//
void MRFBackProfileDlg::SetSelectorListSourceSurf(const CATUnicodeString ipSourceSurf)
{
	_selectorListResultJoinSurface->ClearLine();
	_selectorListResultJoinSurface->SetLine(ipSourceSurf);
	SetFocusOnSelectorList(_selectorListResultJoinSurface);

}
//------------Function to set name to be displayed at Surface Selector List ENDS------------//

//------------Function to set name to be displayed at VentGeom Set Selector List STARTS------------//
void MRFBackProfileDlg::SetSelectorListVentGeomSet(const CATUnicodeString ipVentGeomSet)
{
	_selectorListVentSet->ClearLine();
	_selectorListVentSet->SetLine(ipVentGeomSet);
	SetFocusOnSelectorList(_selectorListVentSet);
}
//------------Function to set name to be displayed at VentGeom Selector List ENDS------------//







